import { useApp } from '../context/AppContext';

export default function SectionHeader({ tag, title }) {
  const { dark } = useApp();
  return (
    <div className="mb-10">
      <p className="text-xs font-semibold tracking-[.14em] uppercase text-amber mb-2">{tag}</p>
      <h2 className={`font-serif-display text-4xl md:text-5xl tracking-tight leading-[1.05] ${dark ? 'text-white' : 'text-ink'}`}
        dangerouslySetInnerHTML={{ __html: title }} />
    </div>
  );
}
